-- ============================================================
-- SEED: Conflict-free class schedules for BSIT and BSCPE
-- Each course in a section gets a UNIQUE day+time slot
-- (no two courses share the same day AND time within one section)
-- Rev. 24 May 2026 v2
-- ============================================================
USE eacdb;
SET SQL_SAFE_UPDATES = 0;

-- ── 1. Wipe old schedules for these sections ─────────────────
DELETE cs_sch FROM class_schedules cs_sch
JOIN class_sections cs ON cs_sch.section_id = cs.section_id
WHERE cs.section_code LIKE 'BSIT-%' OR cs.section_code LIKE 'BSCPE-%';

-- ── 2. Assign ONE unique slot per course per section ─────────
-- Slot index = rn - 1 (0-indexed within each section_code group)
-- day  = (slot_idx MOD 5) + 1   → Mon=1, Tue=2, Wed=3, Thu=4, Fri=5
-- time = slot_idx DIV 5          → 0=07:30, 1=09:00, 2=10:30, 3=13:00
-- With 5 days x 4 time blocks = 20 unique slots per section (covers up to 20 subjects)
-- No second-meeting-day overlap issue since each course gets exactly ONE row.

SELECT
    cs.section_id,
    ((ranked.rn - 1) MOD 5) + 1 AS day_of_week,
    ELT(((ranked.rn - 1) DIV 5) + 1,
        '07:30:00', '09:00:00', '10:30:00', '13:00:00', '14:30:00')  AS start_time,
    ELT(((ranked.rn - 1) DIV 5) + 1,
        '09:00:00', '10:30:00', '12:00:00', '14:30:00', '16:00:00')  AS end_time
FROM (
    SELECT
        cs2.section_id,
        ROW_NUMBER() OVER (
            PARTITION BY cs2.section_code    -- rank within each section group
            ORDER BY cs2.section_id          -- deterministic order
        ) AS rn
    FROM class_sections cs2
    WHERE cs2.section_code LIKE 'BSIT-%'
       OR cs2.section_code LIKE 'BSCPE-%'
) ranked
JOIN class_sections cs ON cs.section_id = ranked.section_id;

-- ── 3. Verify — check Year 1 Sem 1 has no overlaps ──────────
SELECT
    cs.section_code,
    c.course_code,
    CASE sch.day_of_week
        WHEN 1 THEN 'Mon' WHEN 2 THEN 'Tue' WHEN 3 THEN 'Wed'
        WHEN 4 THEN 'Thu' WHEN 5 THEN 'Fri'
    END AS day,
    TIME_FORMAT(sch.start_time,'%H:%i') AS start,
    TIME_FORMAT(sch.end_time,'%H:%i')   AS end
FROM class_sections cs
JOIN courses c ON cs.course_id = c.course_id
JOIN class_schedules sch ON cs.section_id = sch.section_id
WHERE cs.section_code IN ('BSIT-1-1-A','BSIT-1-1-B')
ORDER BY cs.section_code, sch.day_of_week, sch.start_time;

SET SQL_SAFE_UPDATES = 1;
-- ============================================================
-- SEED: Open sections for BSIT and BSCPE (testing only)
-- 2 sections per program per year/sem, status = 'Open'
-- Adds an active 2025-2026 academic term if missing.
-- Rev. 24 May 2026
-- ============================================================
USE eacdb;
SET FOREIGN_KEY_CHECKS = 0;
SET SQL_SAFE_UPDATES = 0;  -- required for MySQL Workbench safe mode

-- ── 1. Ensure a 2025-2026 active academic term exists ────────
ON DUPLICATE KEY UPDATE
  status    = VALUES(status),
  is_active = VALUES(is_active);

-- Mark term 10 as the one active term
UPDATE academic_terms SET is_active = 0 WHERE term_id NOT IN (10);
UPDATE academic_terms SET status = 'ACTIVE', is_active = 1 WHERE term_id = 10;

-- ── 2. Delete old Planning sections for BSIT / BSCPE ─────────
-- (keeps only sections we recreate below with 'Open' status)
DELETE FROM class_sections
WHERE section_code LIKE 'BSIT-%' OR section_code LIKE 'BSCPE-%';

-- ── Helper: Get all BSIT courses per year/sem (curriculum_id 1 OR 15) ──
-- ── Helper: Get all BSCPE courses per year/sem (curriculum_id 16) ──────

-- ── 3. Create 2 OPEN sections per year/sem for BSIT ─────────
-- We create one row per course per section (A and B)

SELECT
    cc.course_id,
    10,
    CONCAT('BSIT-', cc.year_level, '-', cc.semester_number, '-A'),
    NULL,
    40,
    'Open',
    cc.semester_number
FROM curriculum_courses cc
JOIN curriculum_templates ct ON cc.curriculum_id = ct.curriculum_id
JOIN programs p ON ct.program_id = p.program_id
WHERE p.program_code = 'BSIT'
  AND ct.curriculum_id = 1
ON DUPLICATE KEY UPDATE section_status = 'Open';

SELECT
    cc.course_id,
    10,
    CONCAT('BSIT-', cc.year_level, '-', cc.semester_number, '-B'),
    NULL,
    40,
    'Open',
    cc.semester_number
FROM curriculum_courses cc
JOIN curriculum_templates ct ON cc.curriculum_id = ct.curriculum_id
JOIN programs p ON ct.program_id = p.program_id
WHERE p.program_code = 'BSIT'
  AND ct.curriculum_id = 1
ON DUPLICATE KEY UPDATE section_status = 'Open';

-- ── 4. Create 2 OPEN sections per year/sem for BSCPE ────────
SELECT
    cc.course_id,
    10,
    CONCAT('BSCPE-', cc.year_level, '-', cc.semester_number, '-A'),
    NULL,
    40,
    'Open',
    cc.semester_number
FROM curriculum_courses cc
JOIN curriculum_templates ct ON cc.curriculum_id = ct.curriculum_id
JOIN programs p ON ct.program_id = p.program_id
WHERE p.program_code = 'BSCPE'
  AND ct.curriculum_id = 16
ON DUPLICATE KEY UPDATE section_status = 'Open';

SELECT
    cc.course_id,
    10,
    CONCAT('BSCPE-', cc.year_level, '-', cc.semester_number, '-B'),
    NULL,
    40,
    'Open',
    cc.semester_number
FROM curriculum_courses cc
JOIN curriculum_templates ct ON cc.curriculum_id = ct.curriculum_id
JOIN programs p ON ct.program_id = p.program_id
WHERE p.program_code = 'BSCPE'
  AND ct.curriculum_id = 16
ON DUPLICATE KEY UPDATE section_status = 'Open';

-- ── 5. Verify ────────────────────────────────────────────────
SELECT
    SUBSTRING_INDEX(cs.section_code, '-', 3)    AS section_group,
    COUNT(*)                                     AS subject_count,
    cs.section_status
FROM class_sections cs
WHERE cs.section_code LIKE 'BSIT-%' OR cs.section_code LIKE 'BSCPE-%'
GROUP BY section_group, cs.section_status
ORDER BY section_group;

